function createRenderer() {
  function easeOutCubic(x) { return 1 - Math.pow(1 - Math.max(0, Math.min(1, x)), 3); }
  function easeInOut(x) { x = Math.max(0, Math.min(1, x)); return x < 0.5 ? 2 * x * x : 1 - Math.pow(-2 * x + 2, 2) / 2; }
  function roundedRect(ctx, x, y, w, h, r) { ctx.beginPath(); ctx.moveTo(x + r, y); ctx.lineTo(x + w - r, y); ctx.quadraticCurveTo(x + w, y, x + w, y + r); ctx.lineTo(x + w, y + h - r); ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h); ctx.lineTo(x + r, y + h); ctx.quadraticCurveTo(x, y + h, x, y + h - r); ctx.lineTo(x, y + r); ctx.quadraticCurveTo(x, y, x + r, y); ctx.closePath(); }
  function drawGrid(ctx, w, h, t) { ctx.save(); ctx.globalAlpha = 0.18; ctx.strokeStyle = '#25415f'; ctx.lineWidth = 1; for (var x = -80; x < w + 80; x += 48) { ctx.beginPath(); ctx.moveTo(x + (t * 14) % 48, 0); ctx.lineTo(x - 180 + (t * 14) % 48, h); ctx.stroke(); } for (var y = 0; y < h; y += 48) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(w, y); ctx.stroke(); } ctx.restore(); }
  function render(t, context) {
    var ctx = context.mainContext || context.ctx;
    var w = context.width;
    var h = context.height;
    var intro = easeOutCubic(t / 1.2);
    var reveal = easeInOut((t - 0.8) / 2.2);
    var pulse = 0.5 + 0.5 * Math.sin(t * 3.2);

    var bg = ctx.createLinearGradient(0, 0, w, h);
    bg.addColorStop(0, '#09111f');
    bg.addColorStop(0.5, '#10233a');
    bg.addColorStop(1, '#132318');
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, w, h);
    drawGrid(ctx, w, h, t);

    ctx.save();
    ctx.globalAlpha = 0.16;
    ctx.fillStyle = '#7bd88f';
    ctx.beginPath();
    ctx.arc(w * 0.78, h * 0.24, 210 + pulse * 26, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = '#f2aa4c';
    ctx.beginPath();
    ctx.arc(w * 0.24, h * 0.76, 180 + Math.sin(t * 2) * 18, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    var productX = 720 + (1 - intro) * 120;
    var productY = 116 - (1 - intro) * 40;
    var productW = 330;
    var productH = 470;
    ctx.save();
    ctx.translate(productX + productW / 2, productY + productH / 2);
    ctx.rotate((-4 + Math.sin(t * 0.9) * 1.5) * Math.PI / 180);
    ctx.translate(-productW / 2, -productH / 2);
    ctx.globalAlpha = intro;
    ctx.shadowColor = 'rgba(0,0,0,.45)';
    ctx.shadowBlur = 38;
    ctx.shadowOffsetY = 22;
    roundedRect(ctx, 0, 0, productW, productH, 34);
    var body = ctx.createLinearGradient(0, 0, productW, productH);
    body.addColorStop(0, '#f7fafc');
    body.addColorStop(0.55, '#dfe7ef');
    body.addColorStop(1, '#b8c5d2');
    ctx.fillStyle = body;
    ctx.fill();
    ctx.shadowBlur = 0;
    ctx.fillStyle = '#111827';
    roundedRect(ctx, 34, 42, productW - 68, 260, 24);
    ctx.fill();
    var screen = ctx.createLinearGradient(34, 42, productW - 34, 302);
    screen.addColorStop(0, '#0ea5e9');
    screen.addColorStop(1, '#22c55e');
    ctx.globalAlpha = 0.92;
    roundedRect(ctx, 46, 54, productW - 92, 236, 20);
    ctx.fillStyle = screen;
    ctx.fill();
    ctx.globalAlpha = 1;
    ctx.fillStyle = '#111827';
    ctx.font = '900 34px Arial';
    ctx.textAlign = 'center';
    ctx.fillText('ui2v', productW / 2, 368);
    ctx.font = '18px Arial';
    ctx.fillStyle = '#4b5563';
    ctx.fillText('Render Engine', productW / 2, 398);
    ctx.fillStyle = '#f2aa4c';
    ctx.beginPath();
    ctx.arc(productW / 2, 432, 18 + pulse * 3, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();

    ctx.save();
    ctx.globalAlpha = intro;
    ctx.textAlign = 'left';
    ctx.fillStyle = '#eef6ff';
    ctx.font = '900 66px Arial, sans-serif';
    ctx.fillText('Launch-ready', 86, 150);
    ctx.fillText('video rendering', 86, 222);
    ctx.fillStyle = '#a9bdd2';
    ctx.font = '24px Arial, sans-serif';
    ctx.fillText('JSON in. Browser-native Canvas and WebCodecs out.', 90, 280);
    ctx.fillText('Built for AI-generated motion systems and CLI workflows.', 90, 316);
    ctx.restore();

    var cards = [
      ['Canvas', 'browser-native frames'],
      ['WebCodecs', 'hardware-aware MP4'],
      ['Runtime', 'deterministic timeline']
    ];
    for (var i = 0; i < cards.length; i++) {
      var p = easeOutCubic((t - 1.1 - i * 0.22) / 0.8);
      var x0 = 90 + i * 184;
      var y0 = 392 + (1 - p) * 24;
      ctx.save();
      ctx.globalAlpha = p;
      ctx.fillStyle = 'rgba(6, 12, 24, .58)';
      ctx.strokeStyle = i === 1 ? '#f2aa4c' : 'rgba(255,255,255,.18)';
      ctx.lineWidth = 1.5;
      roundedRect(ctx, x0, y0, 156, 104, 12);
      ctx.fill();
      ctx.stroke();
      ctx.fillStyle = i === 1 ? '#f2aa4c' : '#7bd88f';
      ctx.font = '800 20px Arial';
      ctx.fillText(cards[i][0], x0 + 18, y0 + 36);
      ctx.fillStyle = '#b8c8d8';
      ctx.font = '15px Arial';
      ctx.fillText(cards[i][1], x0 + 18, y0 + 66);
      ctx.restore();
    }

    ctx.save();
    ctx.globalAlpha = reveal;
    ctx.fillStyle = '#f2aa4c';
    roundedRect(ctx, 90, 548, 228, 48, 10);
    ctx.fill();
    ctx.fillStyle = '#111827';
    ctx.font = '900 18px Arial';
    ctx.textAlign = 'center';
    ctx.fillText('EXPORT MP4', 204, 579);
    ctx.fillStyle = '#d7e6f4';
    ctx.textAlign = 'left';
    ctx.font = '18px Arial';
    ctx.fillText('6s product showcase example', 342, 579);
    ctx.restore();
  }
  return { render: render };
}
